<script setup>
import { router, useForm } from '@inertiajs/vue3';
import { computed, ref } from 'vue';
import PortalLayout from '../../Layouts/PortalLayout.vue';
import SectionTitle from '../../Components/SectionTitle.vue';

const props = defineProps({ sports: Array, categories: Array, regulations: Array, audits: Array });
const tab = ref('sports');
const sportForm = useForm({ code: '', name: '', type: 'sport', default_format: 'knockout', score_template: '' });
const categoryForm = useForm({ sport_id: '', code: '', name: '', competition_type: 'single', min_members: 1, max_members: 1, scoring_type: 'points', bracket_enabled: true, sort_order: 0, is_active: true });
const regulationForm = useForm({ sport_id: '', title: '', content: '', document_url: '' });
const activeSports = computed(() => props.sports.filter((item) => item.is_active).length);
const activeCategories = computed(() => props.categories.filter((item) => item.is_active).length);
const tabs = computed(() => [
  { id: 'sports', label: 'Cabor', count: props.sports.length },
  { id: 'categories', label: 'Kategori', count: props.categories.length },
  { id: 'regulations', label: 'Regulasi', count: props.regulations.length },
  { id: 'audit', label: 'Audit', count: props.audits.length },
]);

const addSport = () => sportForm.post('/admin/master-data/sports', { onSuccess: () => sportForm.reset() });
const addCategory = () => categoryForm.post('/admin/master-data/categories', { onSuccess: () => categoryForm.reset() });
const addRegulation = () => regulationForm.post('/admin/master-data/regulations', { onSuccess: () => regulationForm.reset() });
const updateSport = (sport) => router.put(`/admin/master-data/sports/${sport.id}`, sport, { preserveScroll: true });
const updateCategory = (category) => router.put(`/admin/master-data/categories/${category.id}`, category, { preserveScroll: true });
</script>

<template>
  <PortalLayout portal="admin">
    <div class="page-head"><SectionTitle eyebrow="Phase 2 · Selesai" title="Master Data Lomba" meta="Sumber data resmi kompetisi" /></div>

    <section class="overview-card">
      <div><span>Master Data</span><h2>Kelola fondasi lomba dari satu tempat.</h2><p>Cabor, kategori, dan regulasi tersimpan terstruktur. Perubahan penting masuk audit secara otomatis.</p></div>
      <dl><div><dt>Cabor Aktif</dt><dd>{{ activeSports }}</dd></div><div><dt>Kategori Aktif</dt><dd>{{ activeCategories }}</dd></div><div><dt>Versi Regulasi</dt><dd>{{ regulations.length }}</dd></div></dl>
    </section>

    <nav class="tabs" aria-label="Master data"><button v-for="item in tabs" :key="item.id" type="button" :class="{ active: tab === item.id }" @click="tab = item.id"><span>{{ item.label }}</span><b>{{ item.count }}</b></button></nav>

    <section v-if="tab === 'sports'" class="master-grid">
      <form class="form-card" @submit.prevent="addSport"><header><span>Data Baru</span><h2>Tambah Cabor</h2><p>Buat master cabor sebelum menambahkan kategori.</p></header><div class="form-body"><label>Kode<input v-model="sportForm.code" placeholder="Contoh: FUTSAL" required /><small v-if="sportForm.errors.code">{{ sportForm.errors.code }}</small></label><label>Nama<input v-model="sportForm.name" placeholder="Nama cabang olahraga" required /><small v-if="sportForm.errors.name">{{ sportForm.errors.name }}</small></label><div class="field-pair"><label>Tipe<select v-model="sportForm.type"><option value="sport">Olahraga</option><option value="seminar">Seminar</option></select></label><label>Format<select v-model="sportForm.default_format"><option value="knockout">Knockout</option><option value="group">Grup</option><option value="round_robin">Round Robin</option><option value="ranking">Ranking</option></select></label></div><label>Template Skor<input v-model="sportForm.score_template" placeholder="Contoh: goals atau points" /></label></div><footer><button class="primary-button" :disabled="sportForm.processing">{{ sportForm.processing ? 'Menyimpan…' : 'Tambah Cabor' }}</button></footer></form>
      <div class="table-card"><header><div><span>Daftar Master</span><h2>Cabor Tersedia</h2></div><b>{{ sports.length }} data</b></header><div class="table-scroll"><table><thead><tr><th>Cabor</th><th>Format</th><th>Status</th><th></th></tr></thead><tbody><tr v-for="sport in sports" :key="sport.id"><td><div class="editable-name"><input v-model="sport.name" /><small>{{ sport.code }} · {{ sport.categories_count }} kategori · {{ sport.events_count }} kompetisi</small></div></td><td><select v-model="sport.default_format"><option value="knockout">Knockout</option><option value="group">Grup</option><option value="round_robin">Round Robin</option><option value="ranking">Ranking</option></select></td><td><select v-model="sport.is_active" :class="['status-select', sport.is_active ? 'active' : 'inactive']"><option :value="true">Aktif</option><option :value="false">Nonaktif</option></select></td><td><button class="outline-button" type="button" @click="updateSport(sport)">Simpan</button></td></tr></tbody></table></div></div>
    </section>

    <section v-else-if="tab === 'categories'" class="master-grid">
      <form class="form-card" @submit.prevent="addCategory"><header><span>Data Baru</span><h2>Tambah Kategori</h2><p>Atur tipe lomba dan batas jumlah pemain.</p></header><div class="form-body"><label>Cabor<select v-model="categoryForm.sport_id" required><option value="">Pilih cabor</option><option v-for="sport in sports" :key="sport.id" :value="sport.id">{{ sport.name }}</option></select></label><div class="field-pair"><label>Kode<input v-model="categoryForm.code" placeholder="PUTRA" required /></label><label>Nama<input v-model="categoryForm.name" placeholder="Putra" required /></label></div><label>Tipe<select v-model="categoryForm.competition_type"><option value="single">Tunggal</option><option value="doubles">Ganda</option><option value="team">Tim</option></select></label><div class="field-pair"><label>Minimum Pemain<input v-model="categoryForm.min_members" type="number" min="1" /></label><label>Maksimum Pemain<input v-model="categoryForm.max_members" type="number" min="1" /></label></div><label>Tipe Skor<input v-model="categoryForm.scoring_type" placeholder="goals, points, time" required /></label></div><footer><button class="primary-button" :disabled="categoryForm.processing">{{ categoryForm.processing ? 'Menyimpan…' : 'Tambah Kategori' }}</button></footer></form>
      <div class="table-card"><header><div><span>Daftar Master</span><h2>Kategori Lomba</h2></div><b>{{ categories.length }} data</b></header><div class="table-scroll"><table><thead><tr><th>Kategori</th><th>Pemain</th><th>Status</th><th></th></tr></thead><tbody><tr v-for="category in categories" :key="category.id"><td><div class="editable-name"><input v-model="category.name" /><small>{{ category.sport.name }} · {{ category.code }}</small></div></td><td><div class="range"><input v-model="category.min_members" type="number" min="1" /><span>–</span><input v-model="category.max_members" type="number" min="1" /></div></td><td><select v-model="category.is_active" :class="['status-select', category.is_active ? 'active' : 'inactive']"><option :value="true">Aktif</option><option :value="false">Nonaktif</option></select></td><td><button class="outline-button" type="button" @click="updateCategory(category)">Simpan</button></td></tr></tbody></table></div></div>
    </section>

    <section v-else-if="tab === 'regulations'" class="master-grid">
      <form class="form-card" @submit.prevent="addRegulation"><header><span>Versi Baru</span><h2>Terbitkan Regulasi</h2><p>Versi lama tetap tersimpan dan tidak ditimpa.</p></header><div class="form-body"><label>Cabor<select v-model="regulationForm.sport_id" required><option value="">Pilih cabor</option><option v-for="sport in sports" :key="sport.id" :value="sport.id">{{ sport.name }}</option></select></label><label>Judul<input v-model="regulationForm.title" placeholder="Regulasi Futsal 2026" required /></label><label>Isi Regulasi<textarea v-model="regulationForm.content" rows="8" placeholder="Ringkasan regulasi yang berlaku…" required /></label><label>URL Dokumen Technical Meeting<input v-model="regulationForm.document_url" type="url" placeholder="https://…" /></label></div><footer><button class="primary-button" :disabled="regulationForm.processing">{{ regulationForm.processing ? 'Menerbitkan…' : 'Terbitkan Versi Baru' }}</button></footer></form>
      <div class="table-card"><header><div><span>Riwayat Versi</span><h2>Regulasi Terbit</h2></div><b>{{ regulations.length }} versi</b></header><div class="table-scroll"><table><thead><tr><th>Regulasi</th><th>Versi</th><th>Status Dokumen</th></tr></thead><tbody><tr v-for="item in regulations" :key="item.id"><td><div class="regulation-title"><strong>{{ item.title }}</strong><small>{{ item.sport.name }}</small></div></td><td><span class="version-badge">v{{ item.version }}</span></td><td><a v-if="item.document_url" class="document-link" :href="item.document_url" target="_blank" rel="noopener">Buka dokumen <span>↗</span></a><span v-else class="muted">Belum tersedia</span></td></tr></tbody></table></div></div>
    </section>

    <section v-else class="table-card audit-card"><header><div><span>Jejak Perubahan</span><h2>Audit Master Data</h2></div><b>{{ audits.length }} aktivitas terbaru</b></header><div class="table-scroll"><table><thead><tr><th>Entitas</th><th>Aksi</th><th>Waktu</th></tr></thead><tbody><tr v-for="item in audits" :key="item.id"><td><strong>{{ item.entity_type.replaceAll('_', ' ') }}</strong><small>ID #{{ item.entity_id }}</small></td><td><span class="audit-badge">{{ item.action }}</span></td><td class="muted">{{ item.created_at }}</td></tr></tbody></table></div></section>
  </PortalLayout>
</template>

<style scoped>
