ground:#fff; border:1px solid #bfd0dc; }.outline-button:hover { background:#eff5fb; border-color:#8fb0ca; }.table-scroll { overflow:auto; }table { width:100%; min-width:680px; border-collapse:collapse; }th,td { padding:13px 15px; border-bottom:1px solid #e7edf0; text-align:left; vertical-align:middle; }th { color:#657681; background:#f7f9fa; font-size:10px; font-weight:800; letter-spacing:.08em; text-transform:uppercase; }tbody tr { transition:background .15s ease; }tbody tr:hover { background:#fbfdfe; }tbody tr:last-child td { border-bottom:0; }td small { display:block; margin-top:4px; color:#7a8993; }.editable-name { min-width:210px; }.editable-name input { min-width:180px; font-weight:750; }.range { display:grid; grid-template-columns:66px auto 66px; align-items:center; gap:6px; }.status-select { min-width:105px; font-weight:750; }.status-select.active { color:#087365; background:#eefaf6; border-color:#b9e3d6; }.status-select.inactive { color:#a1432e; background:#fff4ef; border-color:#efcfc4; }.regulation-title strong { color:#1d3041; }.version-badge,.audit-badge { display:inline-flex; padding:5px 8px; border-radius:999px; font-size:10px; font-weight:850; }.version-badge { color:#1946a3; background:#eaf1ff; border:1px solid #ccdaf7; }.audit-badge { color:#745b00; background:#fff5cf; border:1px solid #eedb94; text-transform:capitalize; }.document-link { color:#1946a3; font-size:12px; font-weight:800; text-decoration:none; }.document-link:hover { text-decoration:underline; }.muted { color:#7c8b95; font-size:12px; }.audit-card { max-width:none; }@media(max-width:1100px){.overview-card{grid-template-columns:1fr}.master-grid{grid-template-columns:320px minmax(0,1fr)}}@media(max-width:900px){.overview-card{padding:22px}.overview-card dl{grid-template-columns:1fr}.overview-card dl div{border-right:0;border-bottom:1px solid rgba(255,255,255,.13)}.master-grid{grid-template-columns:1fr}.form-card{position:static}.tabs{width:100%;overflow:auto}.tabs button{flex:1;justify-co